refentry.refsect1:
&reftitle.description;

 public Ds\SeqDs\Seq::filter
 callablecallback&null;



  Creates a new seq using a callable to
  determine which values to include.

  &reftitle.examples;

   Ds\Seq::filter example using callback function


<?php
$seq = new \Ds\Seq([1, 2, 3, 4, 5]);

var_dump($seq->filter(function($value) {
    return $value % 2 == 0;
}));
?>


   &example.outputs.similar;


object(Ds\Seq)#3 (2) {
  [0]=>
  int(2)
  [1]=>
  int(4)
}




   Ds\Seq::filter example without a callback function


<?php
$seq = new \Ds\Seq([0, 1, 'a', true, false]);

var_dump($seq->filter());
?>


   &example.outputs.similar;


object(Ds\Seq)#2 (3) {
  [0]=>
  int(1)
  [1]=>
  string(1) "a"
  [2]=>
  bool(true)
}
